import{bV as e,aL as i,u as a,G as l}from"./chunks/framework.BfzMay2U.js";const k=JSON.parse('{"title":"MySQL 索引以及 BTree 和 B+Tree","description":"","frontmatter":{},"headers":[],"relativePath":"posts/mysql-index-b-tree.md","filePath":"posts/mysql-index-b-tree.md"}'),p={name:"posts/mysql-index-b-tree.md"};function d(o,s,t,n,c,h){return i(),a("div",null,[...s[0]||(s[0]=[l('<h1 id="mysql-索引以及-btree-和-b-tree" tabindex="-1">MySQL 索引以及 BTree 和 B+Tree <a class="header-anchor" href="#mysql-索引以及-btree-和-b-tree" aria-label="Permalink to &quot;MySQL 索引以及 BTree 和 B+Tree&quot;">​</a></h1><h2 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to &quot;索引&quot;">​</a></h2><ul><li>相当于目录</li><li><strong>是帮助 MySQL 高效获取数据的数据结构</strong></li><li>在 MySQL 中，数据最终是保存在硬盘上的</li></ul><blockquote><p>访问硬盘相当于是<code>IO</code>操作，MySQL 有一个<code>page</code>的概念，一个<code>page</code>就是树中的一个节点，每次 MySQL 就会取出一个<code>page</code>也就是一个节点的数据，而 MySQL 默认一个<code>page</code>保存<code>16k</code>的数据，当然这个是可以改配置修改的。</p></blockquote><p>本质的优化：就是减少<code>IO</code>的次数，一个<code>page</code>保存更多的有效数据。</p><h3 id="二叉树" tabindex="-1">二叉树 <a class="header-anchor" href="#二叉树" aria-label="Permalink to &quot;二叉树&quot;">​</a></h3><ul><li>左子树的所有值都小于根节点</li><li>右子树的所有值都大于根节点</li><li>每个根节点最多分裂出两个子节点</li></ul><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920201743.png" alt="二叉树" loading="lazy"></p><p>比如，我们要查找数字 9，从根节点开始，比根节点小，就从根节点左边开始查，又比左子树大，转而查找右子树，最终找到</p><p>这里经过了<code>10-&gt;8-&gt;9</code>3 个节点，相当于经历了 3 次<code>IO</code>操作。</p><p>这样看起来还算是查询比较少的，但是如果有下面的特例：</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920202137.png" alt="链表格式" loading="lazy"></p><p>这样的树相当于一个链表格式，极端情况下，查找数字 7 就会经历 7 个节点，也就是 7 次<code>IO</code>，就会遍历整个表，所以就衍生出下一个<strong>平衡二叉树</strong></p><h3 id="平衡二叉树" tabindex="-1">平衡二叉树 <a class="header-anchor" href="#平衡二叉树" aria-label="Permalink to &quot;平衡二叉树&quot;">​</a></h3><ul><li>相对平衡，左右两个子树的深度差绝对值不能超过 1，就会避免上述的极端情况</li><li>左右 2 个子树也必须是平衡二叉树</li></ul><blockquote><p>为啥 MySQL 又不用这个呢，是因为二叉树一个节点只有 2 个叉，只能保存一条数据 ，获取 16k 的<code>page</code>，只有一条数据，造成资源浪费。</p></blockquote><p><strong>单个节点保存数据少，就会造成节点增多，树的深度就会增多，查询次数就会增多。</strong></p><h2 id="b-tree" tabindex="-1">B-Tree <a class="header-anchor" href="#b-tree" aria-label="Permalink to &quot;B-Tree&quot;">​</a></h2><p>特点：多叉，阶；<strong>B 树约束了层高，B 树的叶子节点在统一的高度上面</strong></p><ul><li>1 个节点可以存储超过 2 个元素，可以拥有超过 2 个子节点</li><li>拥有二叉树的一些性质</li><li>平衡、每个节点的所有子树高度一致</li><li>比较矮【层数低】</li></ul><p>性质：<code>m</code>阶【阶表示有多少个叉】B 数，最多拥有<code>m</code>个子节点</p><p>元素个数：假设一个节点存储的元素个数为<code>x</code></p><ul><li>根节点：<code>1 &lt;= x &lt;= m-1</code></li><li>非根节点：(向上取整)<code>m/2 &lt;= x &lt;= m - 1</code></li></ul><p>子节点个数：<code>y = x + 1</code></p><ul><li>根节点：<code>2 &lt;= y &lt;= m</code></li><li>非根节点：(向上取整)<code>m/2 &lt;= y &lt;= m</code></li><li>每个节点最多有<code>m</code>个子节点</li><li>除根节点外，每个节点至少有<code>m/2</code>个子节点，注意如果结果除不尽，就向上取整</li><li>根节点要么为空，要么就是独根，否则至少有 2 个子节点</li><li>有<code>k</code>个子节点的节点必须有<code>k</code>个关键词，就是有<code>m</code>个数据就有<code>m</code>个叉</li><li>叶子节点的高度一致</li></ul><p>画一个 BTree</p><p>首先确定一个阶数：4 阶，则每个节点的元素个数为 3</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920203921.png" alt="first_step" loading="lazy"></p><p>首先每个个元素由对应 id 和值组成。我们画出 4 个，然后现在元素个数已经是超出 3 个了，就需要分层，一般取中间的值，自己定下去中间靠前的还是中间靠后的，现在是偶数，我们取 id 为 2 的元素，上提，然后会有一个指针<code>p</code>分别指向第一个和第 3 个.</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920204401.png" alt="step2" loading="lazy"></p><p>然后继续往后面添加元素，添加到 6 的时候，就又必须提，还是取中间靠前的，这次是将 4 提上去。</p><p><strong>我这边可能数字标错了，多了 2 个 2，其实下面的 2 应该是 3，后面依次加 1</strong></p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920204853.png" alt="step3" loading="lazy"></p><p>然后继续往后加元素，加到同样超过 3 个的时候就取中间靠前的往上提，加一个指针。</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920205110.png" alt="step4" loading="lazy"></p><p>然后继续加元素，加到 10，又超过 4 个再往上提取第 8 个上去，此时上面一层也达到了超过 3 个元素了，也取中间靠前的，提取 4 再往上。</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920205456.png" alt="step5" loading="lazy"></p><p>这样的一棵的 4 阶 BTree 树就完了。单个节点可以保存多个数据，一次<code>page</code>可以获取更多的有效数据，同时因为分叉增多，数据层级肯定会更小，查询次数就会减少。前面说一个<code>page</code>最多可以 16k 数据，那么一个 3 层的 B 树可以保存<code>16*16*16=4096k</code>的数据，保存的数据还是不多，如果一个表有五百万数据，那么它的层级还是会很深，<code>IO</code>也会变多。</p><p>数据从小到大一次分步在树的不同层级中，进行范围查找，获取范围越大，获取的节点就越多，<code>IO</code>就越多；比如获取从 1 到 10，就会把每一个节点上的值都遍历一遍，这样性能肯定就会有问题。</p><h2 id="b-tree-1" tabindex="-1">B+Tree <a class="header-anchor" href="#b-tree-1" aria-label="Permalink to &quot;B+Tree&quot;">​</a></h2><ul><li>只在叶子节点保存数据信息，非叶子节点不保存，只保存标识和指针信息。</li><li>节点保存的元素个数等于 m，并且左闭右开</li><li>叶子节点通过指针链接，方便范围查找，只需遍历叶子节点</li></ul><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920223040.png" alt="bjiatree" loading="lazy"></p><blockquote><p>为什么 MySQL 使用 B+Tree，而不使用 B-Tree 呢？</p></blockquote><p>算一下，同层的，BTree 可以保存 4096k</p><p>B+Tree，叶子结点基于索引排序更优，非叶子节点不保存数据，保存索引数据更多，一次<code>IO</code>获取更多的目标数据。</p><p>第二层假设保存一个标识或指针需要 6b，那么第二层可以保存：<code>16*1024/6=2730</code>和第三层一样，三层就可以保存：<code>2730*2730*16≈12亿</code>。</p><hr><h3 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h3><p>MySQL 有 2 个重要的存储引擎</p><p>Myisam：文件有：<code>*.frm</code>、<code>*.myi</code>、<code>*.myd</code></p><ul><li>frm 用于保存表的定义信息</li><li><code>myi</code>用于保存索引的信息</li><li><code>myd</code>保存数据信息</li></ul><p>主键索引</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920224240.png" alt="demo1" loading="lazy"></p><p>非主键索引比如<code>name</code>加上索引，都是和主键索引一样最下面保存的是指针，都分别执行表中的一行数据。</p><hr><p>InnoDB 保存了 2 个文件</p><ul><li><code>frm</code>：表的定义信息</li><li><code>ibd</code>：保存了索引信息和数据信息</li></ul><p>主键索引，下面的叶子节点保存了一个真正的数据，当查找该叶子节点就能直接把数据查出来。</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920224748.png" alt="demo2" loading="lazy"></p><p>如果是<code>name</code>索引，它的叶子节点存储的是其主键值，然后再根据主键值去主键索引中依次查找，最终查找到最终的数据。</p><p>那么如果你不创建主键索引呢，不用担心，<code>InnoDB</code>会自动给你创建索引。</p><h2 id="回表" tabindex="-1">回表 <a class="header-anchor" href="#回表" aria-label="Permalink to &quot;回表&quot;">​</a></h2><ul><li><p>尽量避免回表</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/20220920225133.png" alt="demo3" loading="lazy"></p><blockquote><p>上面使用<code>name</code>索引找到主键值，然后再根据主键值去主键索引里找到最终数据，这个过程就是一个回表的过程。</p></blockquote><p>假设现在有一个表，你设置了<code>id</code>索引和<code>name</code>索引，有一个<code>sql</code>语句如下：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> table</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个会触发回表，根据<code>name</code>索引只能获取到<code>id</code>和<code>name</code>但是此时并不能满足 SQL 查询的需要，因为这里是<code>*</code>，假如这里不是<code>*</code>，就不会回表，会直接获取这 2 个数据，不用再去查找整个数据。</p><blockquote><p>所以会有一个尽量不要使用<code>select *</code>来查询的这样的一个原因</p></blockquote></li><li><p>索引覆盖</p><blockquote><p>就是上面同样的内容，只是<code>sql</code>变成了</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> table</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样就不会去回表去查询住建索引。它覆盖完全了，就不用再查整个。</p></blockquote><p><strong>可以考虑将查询的列创建组合索引，避免回表；不过也不能一直增加索引，不然索引数据越来越大也会影响效率，需要进行评估对查询频率较高的列添加索引</strong></p></li></ul><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><ol><li><p>为什么不建议使用<code>uuid</code>当主键，为什么建议主键 ID 是自增的，和 B+Tree 有什么关系？</p><div class="tip custom-block"><p class="custom-block-title">回答</p><p>因为创建索引的时候是按照从小到大的顺序来创建的，根据我们画的步骤来说，我们每次元素都是从最后一个节点依次添加，当不满足大小的时候就会往上提，当一个<code>page</code>放满数据之后，才会放到下一个<code>page</code>中，这样就会保证一个<code>page</code>的充分利用，也就是减少了分叉，也就是减少了获取的次数；而<code>uuid</code>呢，它是没有任何规律的，插入的时候它就不会插入到最后一个上面，它会在这里插一个，那里插入一个，很容易多出分叉出来，到最后可能一个节点就保存了一条数据，就会造成一个<code>page</code>的浪费，所以不会用<code>uuid</code>来当主键。</p></div></li><li><p>MySQL 中的聚簇索引和非聚簇索引如何理解？</p><div class="tip custom-block"><p class="custom-block-title">回答</p><p><code>InnoDB</code>中的主键索引就是聚簇索引，而非主键索引就是非聚簇索引，数据和索引存储在一起的就是聚簇索引，没有存储在一起的就是非聚簇索引；数据必定是和某一个索引绑定在一起的，绑定数据的就是聚簇索引；</p><p><code>Myisam</code>：只有非聚簇索引，它有 3 个文件组成，一个文件只保存索引信息，一个文件只保存数据信息，他们是分开的，他们都是非聚簇索引。</p></div></li><li><p>最左匹配和<code>xxx%</code>查询一定会使用到索引么？</p><blockquote><p>假如创建了<code>name, age, address</code>的索引</p></blockquote><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ? </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">and</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> age </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ? </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">and</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> address</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>从左到右查，先根据<code>name</code>查询出来的数据，然后再此基础上再根据<code>age</code>查询数据，再在此基础上根据<code>address</code>来查询。</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>使用到了索引，直接根据<code>name</code>拿到了数据。</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ? </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">and</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> address</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它只用到了<code>name</code>，因为要查询<code>address</code>就必须依赖<code>age</code>查询出来的数据，这里没有，所以这里只用到了<code>name</code>索引。</p><p>所以<code>name like &#39;aaa%&#39;</code>是用到了索引，但是把百分号放到了前面<code>name like &#39;%aaa&#39;</code>，这个时候就用不到了，因为这块就是模糊的了，不定的，就用不到索引，最左匹配，最左边都是模糊的不知道，所以就不使用索引，这是通俗的说法。</p></li></ol>',65)])])}const g=e(p,[["render",d]]);export{k as __pageData,g as default};
